const body = $json.body || $json;
const documentId = body.documentId || `DOC-${Date.now()}`;
const fileName = body.fileName || body.normalizedFileName || 'Dokument.pdf';
const area = body.area || 'Unsortiert';
const documentType = body.documentType || 'Dokument';
const caseId = body.caseId || '';
const extractedText = body.extractedText || body.text || 'OCR_TEXT_HIER_EINFUEGEN_ODER_OCR_NODE_VORSCHALTEN';

const prompt = `Du bist ein deutscher Behörden-Assistenzanalyst. Analysiere das Dokument sachlich und ohne Rechtsberatung. Trenne sichere Fakten von Vermutungen. Gib ausschließlich JSON zurück.

Schema:
{
  "summary": "kurze Zusammenfassung",
  "risk": "niedrig|mittel|hoch|kritisch",
  "authority": "erkannte Behörde oder leer",
  "referenceNumber": "Aktenzeichen oder leer",
  "deadlineDate": "YYYY-MM-DD oder leer",
  "deadlineTitle": "Titel der Frist oder leer",
  "missingEvidence": ["fehlender Nachweis"],
  "tasks": ["konkrete Aufgabe"],
  "nextStep": "nächster sinnvoller Schritt",
  "findings": ["wichtige Beobachtung"]
}

Dokument:
Bereich: ${area}
Typ: ${documentType}
Dateiname: ${fileName}
Text:
${extractedText}`;

return [{
  json: {
    documentId,
    fileName,
    area,
    documentType,
    caseId,
    extractedText,
    prompt,
    analysisDate: new Date().toISOString().slice(0, 10),
    sheetId: '1FEnhO0S8fZzzoEKbXVLyX6mn6Su25GIZ4bJbtwd3eks'
  }
}];

const base = $('Analyse vorbereiten').item.json;
const raw = $json.output_text || $json.text || $json.content || $json.message || $json;
let parsed;

try {
  parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch (error) {
  parsed = {
    summary: String(raw).slice(0, 500),
    risk: 'mittel',
    authority: '',
    referenceNumber: '',
    deadlineDate: '',
    deadlineTitle: '',
    missingEvidence: [],
    tasks: ['KI-Ergebnis manuell prüfen'],
    nextStep: 'Analyseergebnis prüfen und Fristen manuell abgleichen.',
    findings: ['KI-Antwort konnte nicht vollständig als JSON gelesen werden']
  };
}

const riskMap = {
  niedrig: 'low',
  mittel: 'medium',
  hoch: 'high',
  kritisch: 'critical'
};
const risk = String(parsed.risk || 'mittel').toLowerCase();
const escalation = riskMap[risk] || 'medium';
const analysisId = `AN-${Date.now()}`;
const deadlineId = `F-${Date.now()}`;
const taskId = `A-${Date.now()}`;
const primaryTask = Array.isArray(parsed.tasks) && parsed.tasks.length ? parsed.tasks[0] : parsed.nextStep || 'Dokument prüfen';
const findings = Array.isArray(parsed.findings) ? parsed.findings : [];
const missingEvidence = Array.isArray(parsed.missingEvidence) ? parsed.missingEvidence : [];

return [{
  json: {
    ...base,
    analysisId,
    deadlineId,
    taskId,
    summary: parsed.summary || 'Dokument wurde analysiert.',
    risk: risk || 'mittel',
    escalation,
    authority: parsed.authority || '',
    referenceNumber: parsed.referenceNumber || '',
    deadlineDate: parsed.deadlineDate || '',
    deadlineTitle: parsed.deadlineTitle || `${base.documentType} Frist prüfen`,
    primaryTask,
    nextStep: parsed.nextStep || primaryTask,
    findings: [...findings, ...missingEvidence.map((item) => `Fehlender Nachweis: ${item}`)]
  }
}];
